framework_css:
/*
  Global design system and structure
  Visual style derived from provided design: minimalist, editorial, high-end beauty aesthetic.
*/

/* Typography imports */
@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;500;600;700&family=Cormorant+Garamond:wght@300;400;500;600&display=swap');

:root {
  /* Color palette */
  --color-primary: #B89496;         /* blush accent */
  --color-primary-contrast: #111111;/* deep neutral */
  --color-secondary: #C6A6A8;       /* soft blush variant */
  --color-secondary-light: #E3DEDB; /* pale warm gray */
  --color-bg: #FFFFFF;
  --color-text: #111111;
  --color-text-muted: #C4C4C4;

  --color-success: #4CAF50;
  --color-error: #D32F2F;
  --color-warning: #F9A825;
  --color-info: #1976D2;

  /* Typography */
  --font-heading: 'Playfair Display', Georgia, serif;
  --font-body: 'Cormorant Garamond', 'Times New Roman', serif;

  --font-size-base: 16px;
  --font-size-small: 13px;
  --font-size-nav: 13px;       /* compact uppercase nav */
  --font-size-h1: 40px;        /* page title */
  --font-size-h2: 30px;
  --font-size-h3: 21px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing scale (8px base) */
  --space-xxs: 4px;
  --space-xs: 8px;
  --space-sm: 16px;
  --space-md: 24px;
  --space-lg: 32px;
  --space-xl: 48px;
  --space-xxl: 64px;
  --space-xxxl: 96px;

  /* Layout */
  --container-max-width: 1120px;  /* maintains airy margins on large screens */
}

/* Global reset & base styles */
*, *::before, *::after {
  box-sizing: border-box;
}

html {
  font-size: 100%;
}

body {
  margin: 0;
  padding: 0;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  background-color: var(--color-bg);
  color: var(--color-text);
  font-family: var(--font-body);
  font-size: var(--font-size-base);
  line-height: var(--line-height-relaxed);
  -webkit-font-smoothing: antialiased;
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: none; /* design uses color shift rather than underline */
}

ul,
ol {
  margin: 0;
  padding: 0;
  list-style: none;
}

.container {
  width: 100%;
  max-width: var(--container-max-width);
  margin-left: auto;
  margin-right: auto;
  padding-left: var(--space-lg);
  padding-right: var(--space-lg);
}

/* Header & primary navigation */

.site-header {
  background-color: var(--color-bg);
}

.header-inner {
  padding-top: var(--space-lg);           /* ~32px from top edge to nav */
  padding-bottom: var(--space-lg);
}

.primary-nav {
  display: flex;
  justify-content: center;
}

.primary-nav-list {
  display: flex;
  flex-wrap: wrap;                        /* wraps gracefully on smaller screens */
  gap: 40px;                              /* generous editorial spacing between items */
}

.primary-nav-link {
  font-family: var(--font-heading);
  font-size: var(--font-size-nav);
  font-weight: var(--font-weight-regular);
  letter-spacing: 0.18em;                 /* matches fine uppercase tracking */
  text-transform: uppercase;
  color: var(--color-text);
  padding-bottom: 2px;                    /* small area for hover underline if needed */
  transition: color 150ms ease-out;
}

.primary-nav-link:hover,
.primary-nav-link:focus {
  color: var(--color-primary);
}

.primary-nav-item.is-active .primary-nav-link {
  color: var(--color-primary);
  font-weight: var(--font-weight-medium);
}

/* Main content area */

.site-main {
  flex: 1 0 auto;
}

.content-inner {
  padding-top: var(--space-xxxl);         /* large editorial gap under nav */
  padding-bottom: var(--space-xxxl);
}

/* Page header / title pattern matching the design */

.page-header {
  text-align: center;
  margin-bottom: var(--space-xxl);
}

.page-title {
  margin: 0;
  font-family: var(--font-heading);
  font-size: var(--font-size-h1);
  font-weight: var(--font-weight-regular);
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--color-primary);
}

.page-title-divider {
  display: inline-block;
  width: 60px;
  height: 1px;
  background-color: var(--color-secondary-light);
  margin-top: var(--space-md);
}

/* Footer */

.site-footer {
  border-top: 1px solid var(--color-secondary-light); /* subtle line similar to page divider */
  background-color: var(--color-bg);
  padding-top: var(--space-xl);
  padding-bottom: var(--space-xl);
}

.footer-inner {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--space-md);
}

.footer-nav {
  text-align: center;
}

.footer-nav-list {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 32px;
}

.footer-nav-link {
  font-family: var(--font-heading);
  font-size: var(--font-size-small);
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: var(--color-text);
  opacity: 0.8;
  transition: color 150ms ease-out, opacity 150ms ease-out;
}

.footer-nav-link:hover,
.footer-nav-link:focus {
  color: var(--color-primary);
  opacity: 1;
}

.footer-meta {
  font-size: var(--font-size-small);
  color: var(--color-text-muted);
  text-align: center;
}

.footer-copy {
  margin: 0;
}

/* Utility: update year dynamically via JS if needed; here we simply style the span */
.footer-year {
  white-space: nowrap;
}

/* Responsive adjustments */

@media (max-width: 900px) {
  .header-inner {
    padding-top: var(--space-md);
    padding-bottom: var(--space-md);
  }

  .content-inner {
    padding-top: var(--space-xxl);
    padding-bottom: var(--space-xxl);
  }

  .primary-nav-list {
    gap: 24px;
  }
}

@media (max-width: 600px) {
  .primary-nav-list {
    justify-content: center;
  }

  .primary-nav-link {
    font-size: 12px;
    letter-spacing: 0.16em;
  }

  .page-title {
    font-size: 32px;
  }

  .footer-nav-list {
    gap: 16px;
  }
}
